def compute_feature(ctx):
    stats_a = ctx["stats_a"]
    stats_b = ctx["stats_b"]
    helpers = ctx["helpers"]
    map_a = stats_a["header_to_value"]
    map_b = stats_b["header_to_value"]
    shared = list(set(map_a.keys()).intersection(set(map_b.keys())))
    exact = 0.0
    if shared:
        match_count = 0
        for key in shared:
            if str(map_a.get(key, "")) == str(map_b.get(key, "")):
                match_count += 1
        exact = float(match_count) / float(len(shared))
    header_tok = helpers["token_jaccard"](list(stats_a["header_token_set"]), list(stats_b["header_token_set"]))
    return helpers["clip01"](0.6 * exact + 0.4 * header_tok)
